import { useState, useEffect, useRef } from 'react';
import {
  FiUpload, FiImage, FiTrash2,
  FiChevronLeft, FiChevronRight, FiX, FiLink,
} from 'react-icons/fi';
import {
  getMyProducts, createProduct,
  updateProduct, deleteProduct,
} from '../services/api';
import { useAuth } from '../context/AuthContext';
import { toast } from 'react-toastify';

const EMPTY_FORM = {
  name: '', description: '', price: '', discountPrice: '',
  category: '', stock: '', brand: '',
  images: [],   // mix of File objects and URL strings
};

const BACKEND_URL = 'http://localhost:5000';

/* ─────────────────────────────────────────────────────────────
   Helper — turn a stored image value into a displayable URL
   ──────────────────────────────────────────────────────────── */
const toDisplayUrl = (img) => {
  if (!img) return '';
  if (img instanceof File) return URL.createObjectURL(img);
  if (typeof img === 'string') {
    if (img.startsWith('http') || img.startsWith('blob:') || img.startsWith('data:')) return img;
    return `${BACKEND_URL}/${img.replace(/^\/+/, '')}`;
  }
  return '';
};

/* ─────────────────────────────────────────────────────────────
   Component
   ──────────────────────────────────────────────────────────── */
const SellerDashboard = () => {
  const { user } = useAuth();

  const [products,  setProducts]  = useState([]);
  const [tab,       setTab]       = useState('products');
  const [form,      setForm]      = useState(EMPTY_FORM);
  const [editId,    setEditId]    = useState(null);
  const [uploading, setUploading] = useState(false);
  const [dragging,  setDragging]  = useState(false);
  const [urlInput,  setUrlInput]  = useState('');
  const [showUrl,   setShowUrl]   = useState(false);
  const fileInputRef = useRef(null);

  /* ── load ─────────────────────────────────────────────────── */
  const load = async () => {
    try {
      const res = await getMyProducts();
      setProducts(res.data.products);
    } catch {
      toast.error('Failed to load products');
    }
  };
  useEffect(() => { load(); }, []);

  /* ── image helpers ────────────────────────────────────────── */
  const processFiles = (files) => {
    Array.from(files)
      .filter((f) => f.type.startsWith('image/'))
      .forEach((file) => {
        if (file.size > 5 * 1024 * 1024) {
          toast.error(`${file.name} exceeds 5 MB`);
          return;
        }
        setForm((prev) => ({ ...prev, images: [...prev.images, file] }));
      });
  };

  const onFileInput = (e) => { processFiles(e.target.files); e.target.value = ''; };
  const onDrop      = (e) => { e.preventDefault(); setDragging(false); processFiles(e.dataTransfer.files); };

  const addImageUrl = () => {
    const url = urlInput.trim();
    if (!url || !url.startsWith('http')) { toast.error('Enter a valid URL'); return; }
    if (form.images.includes(url))        { toast.error('Already added');    return; }
    setForm((prev) => ({ ...prev, images: [...prev.images, url] }));
    setUrlInput(''); setShowUrl(false);
  };

  const removeImage = (i) =>
    setForm((prev) => ({ ...prev, images: prev.images.filter((_, idx) => idx !== i) }));

  const moveImage = (i, dir) => {
    const to = i + dir;
    if (to < 0 || to >= form.images.length) return;
    const imgs = [...form.images];
    [imgs[i], imgs[to]] = [imgs[to], imgs[i]];
    setForm((prev) => ({ ...prev, images: imgs }));
  };

  /* ── reset / edit ─────────────────────────────────────────── */
  const resetForm = () => {
    setForm(EMPTY_FORM); setEditId(null);
    setUrlInput(''); setShowUrl(false);
  };

  const handleEdit = (p) => {
    setForm({
      name:          p.name,
      description:   p.description,
      price:         p.price,
      discountPrice: p.discountPrice || '',
      category:      p.category,
      stock:         p.stock,
      brand:         p.brand || '',
      images:        p.images || [],   // existing paths/URLs as strings
    });
    setEditId(p._id);
    setTab('add');
  };

  /* ── delete ───────────────────────────────────────────────── */
  const handleDelete = async (id) => {
    if (!window.confirm('Delete this product?')) return;
    try {
      await deleteProduct(id);
      toast.success('Deleted');
      load();
    } catch {
      toast.error('Delete failed');
    }
  };

  /* ── submit ───────────────────────────────────────────────── */
  const handleSubmit = async (e) => {
    e.preventDefault();

    if (form.images.length === 0) {
      toast.error('Please add at least one image');
      return;
    }

    setUploading(true);

    try {
      const fd = new FormData();

      // ── text fields ──────────────────────────────────────────
      fd.append('name',          form.name);
      fd.append('description',   form.description);
      fd.append('price',         form.price);
      fd.append('discountPrice', form.discountPrice || '');
      fd.append('category',      form.category);
      fd.append('stock',         form.stock);
      fd.append('brand',         form.brand || '');

      // ── images ───────────────────────────────────────────────
      // Separate File objects (new uploads) from strings (existing URLs).
      // Field name MUST match what multer expects on the backend.
      // If your multer is:  upload.array('images')  → field = 'images'  ✅
      // If your multer is:  upload.array('files')   → change to 'files'
      form.images.forEach((img) => {
        if (img instanceof File) {
          fd.append('images', img);           // ← actual file upload
        } else if (typeof img === 'string') {
          fd.append('existingImages', img);   // ← keep existing URL/path
        }
      });

      if (editId) {
        await updateProduct(editId, fd);
        toast.success('Product updated!');
      } else {
        await createProduct(fd);
        toast.success('Submitted for approval!');
      }

      resetForm();
      setTab('products');
      load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Something went wrong');
    } finally {
      setUploading(false);
    }
  };

  /* ── render ───────────────────────────────────────────────── */
  return (
    <div className="admin-page">
      <h1>Seller Dashboard</h1>

      {/* Tabs */}
      <div className="admin-tabs">
        <button
          className={tab === 'products' ? 'active' : ''}
          onClick={() => { resetForm(); setTab('products'); }}
        >
          My Products
        </button>
        <button
          className={tab === 'add' ? 'active' : ''}
          onClick={() => { resetForm(); setTab('add'); }}
        >
          + Add Product
        </button>
      </div>

      {/* ── Products table ───────────────────────────────────── */}
      {tab === 'products' && (
        <table className="admin-table">
          <thead>
            <tr>
              <th>Image</th><th>Name</th><th>Price</th>
              <th>Stock</th><th>Status</th><th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {products.length === 0 && (
              <tr>
                <td colSpan={6} style={{ textAlign: 'center', padding: '2rem', color: '#aaa' }}>
                  No products yet.
                </td>
              </tr>
            )}
            {products.map((p) => (
              <tr key={p._id}>
                <td>
                  {p.images?.[0] ? (
                    <img
                      src={toDisplayUrl(p.images[0])}
                      alt={p.name}
                      style={{ width: 48, height: 60, objectFit: 'cover', borderRadius: 4, border: '1px solid #eee' }}
                    />
                  ) : (
                    <div style={{ width: 48, height: 60, background: '#f5f0e8', borderRadius: 4, display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#ccc', fontSize: 20 }}>
                      <FiImage />
                    </div>
                  )}
                </td>
                <td>{p.name}</td>
                <td>PKR {p.price}</td>
                <td>{p.stock}</td>
                <td>
                  <span className={p.isApproved ? 'badge-green' : 'badge-yellow'}>
                    {p.isApproved ? 'Approved' : 'Pending'}
                  </span>
                </td>
                <td>
                  <button className="btn-sm" onClick={() => handleEdit(p)}>Edit</button>
                  <button className="btn-sm btn-danger" onClick={() => handleDelete(p._id)}>Delete</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* ── Add / Edit form ──────────────────────────────────── */}
      {tab === 'add' && (
        <form className="product-form" onSubmit={handleSubmit}>
          <h2>{editId ? 'Edit Product' : 'Add New Product'}</h2>

          {['name', 'brand', 'category'].map((f) => (
            <input
              key={f}
              placeholder={f.charAt(0).toUpperCase() + f.slice(1)}
              value={form[f]}
              onChange={(e) => setForm((p) => ({ ...p, [f]: e.target.value }))}
              required={f !== 'brand'}
            />
          ))}

          <textarea
            placeholder="Description"
            value={form.description}
            onChange={(e) => setForm((p) => ({ ...p, description: e.target.value }))}
            required
            rows={3}
          />

          <div className="form-row">
            <input
              type="number" placeholder="Price (PKR)" value={form.price}
              onChange={(e) => setForm((p) => ({ ...p, price: e.target.value }))} required
            />
            <input
              type="number" placeholder="Discount Price (optional)" value={form.discountPrice}
              onChange={(e) => setForm((p) => ({ ...p, discountPrice: e.target.value }))}
            />
            <input
              type="number" placeholder="Stock" value={form.stock}
              onChange={(e) => setForm((p) => ({ ...p, stock: e.target.value }))} required
            />
          </div>

          {/* ── Image section ─────────────────────────────────── */}
          <div style={{ marginTop: '1.25rem' }}>
            <label style={{ display: 'block', fontWeight: 600, marginBottom: '0.6rem', fontSize: '0.85rem' }}>
              Product Images <span style={{ color: 'red' }}>*</span>
            </label>

            {/* Drop zone */}
            <div
              onDragEnter={(e) => { e.preventDefault(); setDragging(true);  }}
              onDragOver={(e)  => { e.preventDefault(); setDragging(true);  }}
              onDragLeave={(e) => { e.preventDefault(); setDragging(false); }}
              onDrop={onDrop}
              onClick={() => fileInputRef.current?.click()}
              style={{
                border:       `2px dashed ${dragging ? '#c47878' : '#d0d0d0'}`,
                padding:      '2rem 1.5rem',
                borderRadius: 8,
                textAlign:    'center',
                cursor:       'pointer',
                background:   dragging ? '#fff5f5' : '#fafafa',
                transition:   'all 0.2s',
              }}
            >
              <input
                ref={fileInputRef}
                type="file"
                multiple
                accept="image/*"
                style={{ display: 'none' }}
                onChange={onFileInput}
              />
              <div style={{ fontSize: '2rem', marginBottom: '0.6rem', color: '#aaa' }}>
                {dragging ? <FiUpload /> : <FiImage />}
              </div>
              <p style={{ margin: 0, fontWeight: 600, color: '#444', fontSize: '0.9rem' }}>
                {dragging ? 'Drop images here' : 'Drag & drop images here'}
              </p>
              <p style={{ margin: '0.3rem 0 0.8rem', color: '#aaa', fontSize: '0.78rem' }}>
                PNG, JPG, WEBP — max 5 MB each
              </p>
              <span style={{
                display: 'inline-block',
                padding: '0.45rem 1.25rem',
                background: '#0d1822', color: '#fff',
                borderRadius: 4, fontSize: '0.78rem',
                fontWeight: 600, pointerEvents: 'none',
              }}>
                Attach Files
              </span>
            </div>

            {/* URL input */}
            {!showUrl ? (
              <button
                type="button"
                onClick={() => setShowUrl(true)}
                style={{ marginTop: '0.6rem', background: 'none', border: 'none', color: '#888', fontSize: '0.78rem', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: 4 }}
              >
                <FiLink size={12} /> Or add image by URL
              </button>
            ) : (
              <div style={{ display: 'flex', gap: 8, marginTop: '0.6rem' }}>
                <input
                  autoFocus
                  type="url"
                  value={urlInput}
                  onChange={(e) => setUrlInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addImageUrl())}
                  placeholder="https://example.com/image.jpg"
                  style={{ flex: 1, marginBottom: 0 }}
                />
                <button type="button" className="btn-sm" onClick={addImageUrl}>Add</button>
                <button type="button" className="btn-sm" onClick={() => { setShowUrl(false); setUrlInput(''); }}>
                  <FiX />
                </button>
              </div>
            )}

            {/* Preview grid */}
            {form.images.length > 0 && (
              <div style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill,minmax(88px,1fr))',
                gap: 10, marginTop: '0.9rem',
              }}>
                {form.images.map((img, i) => (
                  <div
                    key={i}
                    style={{
                      position: 'relative', borderRadius: 6, overflow: 'hidden',
                      border: i === 0 ? '2px solid #c4963c' : '1px solid #e0e0e0',
                    }}
                  >
                    <img
                      src={toDisplayUrl(img)}
                      alt=""
                      style={{ width: '100%', aspectRatio: '3/4', objectFit: 'cover', display: 'block' }}
                    />

                    {/* Main badge */}
                    {i === 0 && (
                      <span style={{
                        position: 'absolute', top: 4, left: 4,
                        background: '#0d1822', color: '#c4963c',
                        fontSize: '0.52rem', fontWeight: 700,
                        padding: '2px 5px', letterSpacing: '0.08em',
                        textTransform: 'uppercase', borderRadius: 2,
                      }}>
                        Main
                      </span>
                    )}

                    {/* Controls overlay */}
                    <div
                      style={{
                        position: 'absolute', inset: 0,
                        background: 'rgba(0,0,0,0.55)',
                        display: 'flex', alignItems: 'center', justifyContent: 'center', gap: 5,
                        opacity: 0, transition: 'opacity 0.2s',
                      }}
                      onMouseEnter={(e) => (e.currentTarget.style.opacity = 1)}
                      onMouseLeave={(e) => (e.currentTarget.style.opacity = 0)}
                    >
                      {i > 0 && (
                        <button type="button" style={iconBtnStyle} onClick={() => moveImage(i, -1)}>
                          <FiChevronLeft size={13} />
                        </button>
                      )}
                      <button
                        type="button"
                        style={{ ...iconBtnStyle, background: 'rgba(192,57,43,0.85)' }}
                        onClick={() => removeImage(i)}
                      >
                        <FiTrash2 size={12} />
                      </button>
                      {i < form.images.length - 1 && (
                        <button type="button" style={iconBtnStyle} onClick={() => moveImage(i, 1)}>
                          <FiChevronRight size={13} />
                        </button>
                      )}
                    </div>

                    {/* Index */}
                    <span style={{
                      position: 'absolute', bottom: 3, right: 3,
                      background: 'rgba(0,0,0,0.6)', color: '#fff',
                      fontSize: '0.6rem', padding: '1px 4px', borderRadius: 2,
                    }}>
                      {i + 1}/{form.images.length}
                    </span>
                  </div>
                ))}
              </div>
            )}

            {form.images.length === 0 && (
              <p style={{ fontSize: '0.78rem', color: '#c47878', marginTop: '0.5rem' }}>
                Please add at least one image before submitting
              </p>
            )}

            {form.images.length > 0 && (
              <p style={{ fontSize: '0.72rem', color: '#aaa', marginTop: '0.4rem' }}>
                First image is the main photo. Hover to reorder or remove.
              </p>
            )}
          </div>
          {/* ── End image section ─────────────────────────────── */}

          <div style={{ display: 'flex', gap: 10, marginTop: '1.5rem' }}>
            <button
              type="submit"
              className="btn-primary"
              disabled={uploading || form.images.length === 0}
              style={{ opacity: uploading || form.images.length === 0 ? 0.55 : 1 }}
            >
              {uploading ? 'Submitting…' : editId ? 'Update Product' : 'Submit for Approval'}
            </button>
            <button
              type="button"
              className="btn-ghost"
              onClick={() => { resetForm(); setTab('products'); }}
            >
              Cancel
            </button>
          </div>
        </form>
      )}
    </div>
  );
};

export default SellerDashboard;

const iconBtnStyle = {
  width: 28, height: 28, borderRadius: '50%',
  border: 'none', background: 'rgba(255,255,255,0.2)',
  color: '#fff', cursor: 'pointer',
  display: 'flex', alignItems: 'center', justifyContent: 'center',
};
